import json, os, glob, sys

SRC = os.path.expanduser("~/.claude/projects/-Users-venom-Developer-radiacode-kmp")
OUT = "/tmp/rmp_sessions"
CURRENT = "98f573b0-c435-4b42-bcc2-47f75f4802e9"  # this session, skip

def block_text(c):
    """Return compact text for a content value (str or list of blocks)."""
    out = []
    if isinstance(c, str):
        return c
    if isinstance(c, list):
        for b in c:
            if not isinstance(b, dict):
                continue
            t = b.get("type")
            if t == "text":
                out.append(b.get("text", ""))
            elif t == "tool_use":
                name = b.get("name", "?")
                inp = b.get("input", {}) or {}
                # pick a short descriptor
                desc = ""
                for k in ("description","command","file_path","path","pattern","query","prompt","skill","old_string"):
