                        v = str(inp[k]).replace("\n"," ")
                        desc = f"{k}={v[:120]}"
                        break
                out.append(f"[TOOL {name}] {desc}")
            elif t == "tool_result":
                # heavily truncate tool results
                rc = b.get("content","")
                if isinstance(rc, list):
                    rc = " ".join(x.get("text","") for x in rc if isinstance(x,dict))
                rc = str(rc).replace("\n"," ")
                if rc.strip():
                    out.append(f"[RESULT] {rc[:150]}")
    return "\n".join(x for x in out if x)

for path in glob.glob(os.path.join(SRC, "*.jsonl")):
    sid = os.path.basename(path)[:-6]
