        continue
    lines_out = []
    summary = None
    with open(path, errors="replace") as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            try:
                d = json.loads(line)
            except Exception:
                continue
            typ = d.get("type")
            if typ == "summary":
                summary = d.get("summary")
                continue
            if typ not in ("user","assistant"):
                continue
            msg = d.get("message", {}) or {}
            c = msg.get("content","")
            txt = block_text(c)
            if not txt.strip():
                continue
            role = "USER" if typ == "user" else "ASSISTANT"
